var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"헉... 헉...","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신... 얼마나 약골인 거야? 나 혼자 애 둘을 업고 달리게 만들고 말이지.","JPN":"君……どれだけひ弱なの？　私に子ども2人をおぶって走らせるだなんて。","ENG":"Just how... weak are you? Making me run while carrying two kids all by myself.","TWN":"你……到底有多弱啊？害我一個人揹著兩個人跑。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...미안하군. 타고난 천성 같은 거라서 말이야.","JPN":"……すまない。天性のようなものでね。","ENG":"...My apologies. It's just how I am by nature.","TWN":"……抱歉，這好像是天生的。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 격렬하던 싸움 소리가 안 들릴 정도면... 충분히 멀리 온 거겠지?","JPN":"あの激しい戦闘の音も聞こえなくなったし……十分遠くまで来られたのかな？","ENG":"If we can't even hear the sounds of that intense fight anymore... then we must be far enough away, right?","TWN":"剛才那麼激烈的戰鬥聲都聽不到了……應該已經離得夠遠了吧。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"젠장! 이 망할 낙원을 벗어날 유일한 방법이 막혔어.","JPN":"くそ！　このふざけた楽園から逃れる方法がなくなったよ。","ENG":"Damn it! Now we've lost our way out of this damned paradise.","TWN":"可惡！我們離開這該死的樂園的方法也消失了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"여기 갇혀있는 채로는... 바깥에 있는 사람들을 만날 수조차 없고.","JPN":"こう完全に閉じ込められちゃ……外の人間を助けるどころか、会うことすらできないよ。","ENG":"Trapped here like this... we can't even meet the people outside, let alone help them.","TWN":"被困在這裡的話……別說幫助外面的人，連見到他們都辦不到。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭔가 뾰족한 수가 없을까? 당신이라면 계획이 있을 거잖아!","JPN":"君、本当にこのまま全部諦めるつもりなの？　何か手はないの！？","ENG":"Are you really planning to give up on everything just like this? Isn't there anything we can try?!","TWN":"你真的要就這樣放棄一切嗎？不能再做點什麼嗎！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말했다시피, 늑대 없이는 황금나무를 없앨 방법이 없다네.","JPN":"言った通り、オオカミがいないと黄金の木を消すことはできない。","ENG":"As I said, without the Wolf, there is no way to remove the Golden Tree.","TWN":"我說過了，沒有狼就無法摧毀黃金樹。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보다시피, 난 어린 소녀를 업고 달리는 것조차 못하는 약골이고 말이야.","JPN":"見て分かると思うが、私は小さい女の子をおぶって走ることもできないほど体力がなくてね。","ENG":"As you can see, I'm too weak to even run while carrying a young girl.","TWN":"你也看到了，我是個連揹著小女孩跑步都做不到的無能傢伙。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만...","JPN":"しかし……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람들을 지키기 위해 필요한 이를 만나 도움을 구해볼 수는 있지.","JPN":"他の者の助けがあれば、ここに来る者たちを黄金の木から守ることはできる。","ENG":"With someone else's help, it is still possible to protect those coming here from the Golden Tree.","TWN":"如果有其他人的幫助，就能保護來到這裡的人不被黃金樹排斥。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"도움을 구한다고? 여기서 누굴 찾고 있던 거였어?","JPN":"他の者？　誰を探してるの？","ENG":"Someone else? Who are you looking for?","TWN":"其他人？你要找誰？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼 이렇게 쉬고 있을 때가 아냐. 빨리 그 사람을 찾아야...!","JPN":"時間がない。早くその人を探さないと……！","ENG":"There's no time. We need to find that person quickly–!","TWN":"沒有時間了，必須快點找到那個人……！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 바로 자네일세.","JPN":"君だ。","ENG":"It's you.","TWN":"就是你啊。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"보면 모르겠어? 난 여기 낙원에 갇혀 있다고.","JPN":"見て分からない？　私はここに閉じ込められてるんだよ。","ENG":"Can't you see? I'm trapped here.","TWN":"你看不出來嗎？我被困在這裡。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이런 곳에서, 아무 능력도 없는 내가 무슨 수로...","JPN":"こんな場所で、何の力もない私がどうやって……","ENG":"What am I supposed to do without any abilities, in a place like this…","TWN":"在這種地方，毫無能力的我能做什麼……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다이나 양이 엑자일러에 대해 했던 말을 기억하나?","JPN":"ダイナ君がエグザイラーについて話した内容を覚えているかね。","ENG":"Do you remember what Daina said about Exiles?","TWN":"還記得黛娜小姐說過關於流放者的話嗎？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그들은 낙원의 주민들과 달리 먼 세계에서 온 엑자일러들이야.","JPN":"彼らは楽園の住民とは違い、遠い世界から来たエグザイラーだ。","ENG":"Unlike the residents of the Promised Land, they are Exiles from distant worlds.","TWN":"他們與樂園的居民不同，是來自遙遠世界的流放者。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그리고 황금나무는 엑자일러의 존재를 말소시키는 일종의 척력을 발휘하지.","JPN":"そして黄金の木は世界の意志として、異なる性質を持つエグザイラーを追放しようとする、一種の斥力を発揮する。","ENG":"And the Golden Tree, as the Will of the World, exerts a kind of repulsive force that seeks to expel Exiles with different properties.","TWN":"而黃金樹作為世界的意志，會發揮排斥力驅逐這些異質的流放者。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"황금나무는... 다른 성질을 가진 엑자일러를 추방하려 한다...","JPN":"黄金の木は……異なる性質を持つエグザイラーを追放しようとする……","ENG":"The Golden Tree... tries to expel Exiles with different properties...","TWN":"黃金樹……會驅逐異質的流放者……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세계가 엑자일러를 판단하는 기준은 적개심이나 위험성 같은 게 아닐세.","JPN":"世界がエグザイラーを判断する基準は、敵意や危険性などではない。","ENG":"The standard by which the world judges Exiles is not hostility or danger.","TWN":"世界判斷流放者的標準不是敵意或危險性。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자신의 세계와 같은 성질을 가지고 있느냐, 그렇지 않느냐가 기준으로 작용할 뿐.","JPN":"自分の世界と同じ性質を持っているかどうか、が基準になる。","ENG":"What matters is whether they share the same nature as this world or not.","TWN":"而是他們是否具有與這個世界相同的性質。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니, 자네가 연주를 통해 우리 엑자일러들에게 이 세계의 성질을 부여한다면...","JPN":"だから、君が演奏で彼らにこの世界の性質を与えるんだ。","ENG":"Therefore, through your performance, you must grant them the nature of this world.","TWN":"所以請透過演奏，賦予他們與這個世界相同的性質。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"황금나무는 더 이상 그들의 존재를 밀어내지 않을 거야.","JPN":"黄金の木の斥力が、これ以上彼らの存在を拒まないように。","ENG":"So that the Golden Tree's repulsive force will no longer push their existence away.","TWN":"讓黃金樹不再排斥他們的存在。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래서, 내가 뭘 하면 된다는 건데?","JPN":"それで、私は何をすればいい？","ENG":"So what exactly are you saying I should do?","TWN":"那我該怎麼做？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"멘탈 프린팅.","JPN":"メンタル・プリンティング。","ENG":"Mental Printing.","TWN":"智力複印。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};